def seed():
    now = datetime.now(timezone.utc).isoformat()
    for s in SCENARIOS:
        item = {
            "id": str(uuid.uuid4()),
            "createdAt": now,
            **s,
        }
        table.put_item(Item=item)
        print(f"  Created: {s['name']} ({s['difficulty']})")
    print(f"\nDone! {len(SCENARIOS)} scenarios seeded.")

if __name__ == "__main__":
    seed()
